import React from 'react';

import Tag from './Tag';

import '../../assets/styles/components/blog/Post.scss';

interface PostProps {
  title: string;
  subtitle: string;
  date: number;
  tags?: React.ComponentProps<typeof Tag>[];
  paragraphs: string[];
}

function dateToString(date: Date) {
  const day = date.getDate().toString().padStart(2, '0');
  const month = (date.getMonth() + 1).toString().padStart(2, '0');
  const year = date.getFullYear();

  const hours = date.getHours().toString().padStart(2, '0');
  const minutes = date.getMinutes().toString().padStart(2, '0');

  return `${day}/${month}/${year} - ${hours}:${minutes}`;
}

function Post({ title, date, subtitle, tags, paragraphs }: PostProps) {
  return (
    <article className="Post">
      <hgroup className="Post__header">
        <h2 className="Post__headline1">{title}</h2>
        <h3 className="Post__headline2">{subtitle}</h3>

        <div className="Post__caption">{dateToString(new Date(date))}</div>

        {tags && tags.map(tag =>
          <Tag
            key={`tag-${tag.name}`}
            {...tag}
          />
        )}

      </hgroup>

      {paragraphs.map(paragraph =>
        <p
          key={paragraph}
          className="Post__body"
        >
          {paragraph}
        </p>
      )}

      <footer className="Post__footer">
        {/* <Row>
          <Icon icon="notifications" />
          <Icon icon="notifications" />
        </Row> */}
      </footer>
    </article>
  );
}

export default Post;
